import { handleNetworkError } from '@/account/lib/network-error';
import { fetchGraphQl } from '@/account/api/fetch-graphql';
import { handleFetchError } from '@/account/lib/fetch-error';
import { DELETE_PAYMENT_TOKEN } from './graphql/deletePaymentToken.graphql';
import { DeletePaymentTokenResponse } from '@/account/types';

export const deletePaymentToken = async (
  publicHash: string
): Promise<boolean> => {
  return await fetchGraphQl(DELETE_PAYMENT_TOKEN, {
    method: 'POST',
    variables: { public_hash: publicHash },
  })
    .then((response: DeletePaymentTokenResponse) => {
      if (response.errors?.length) return handleFetchError(response.errors);

      return Boolean(response.data?.deletePaymentToken?.result);
    })
    .catch(handleNetworkError);
};
