import {
  ADDRESS_FRAGMENT,
  ORDER_SUMMARY_FRAGMENT,
  CUSTOMER_ORDER_FRAGMENT,
} from '@/account/api/fragments';

export const GET_CUSTOMER_ORDERS_LIST = /* GraphQL */ `
  query GET_CUSTOMER_ORDERS_LIST(
    $currentPage: Int
    $pageSize: Int
    $filter: CustomerOrdersFilterInput
    $sort: CustomerOrderSortInput
  ) {
    customer {
      returns {
        items {
          uid
          number
          order {
            id
          }
        }
      }
      orders(
        currentPage: $currentPage
        pageSize: $pageSize
        filter: $filter
        sort: $sort
      ) {
        page_info {
          page_size
          total_pages
          current_page
        }
        date_of_first_order
        total_count
        items {
          ...CUSTOMER_ORDER_FRAGMENT
          shipping_address {
            ...ADDRESS_FRAGMENT
          }
          billing_address {
            ...ADDRESS_FRAGMENT
          }
          total {
            ...ORDER_SUMMARY_FRAGMENT
          }
        }
      }
    }
  }
  ${CUSTOMER_ORDER_FRAGMENT}
  ${ADDRESS_FRAGMENT}
  ${ORDER_SUMMARY_FRAGMENT}
`;
