import { AdminAssistanceActionsResponse } from '@/account/types';
import { AdminAssistanceActions } from '@/account/data/models';

export function transformAdminAssistanceActions(
  response: AdminAssistanceActionsResponse
): AdminAssistanceActions | null {
  const adminAssistanceActions =
    response?.data?.customer?.admin_assistance_actions;

  if (!adminAssistanceActions) {
    return null;
  }

  return {
    totalCount: adminAssistanceActions.total_count || 0,
    items:
      adminAssistanceActions.items?.map((item) => ({
        action: item.action || '',
        date: item.date || '',
        details: item.details || '',
      })) || [],
    pageInfo: {
      currentPage: adminAssistanceActions.page_info?.current_page || 1,
      pageSize: adminAssistanceActions.page_info?.page_size || 10,
      totalPages: adminAssistanceActions.page_info?.total_pages || 1,
    },
  };
}
