import { fetchGraphQl } from '@/account/api/fetch-graphql';
import { handleFetchError } from '@/account/lib/fetch-error';
import { handleNetworkError } from '@/account/lib/network-error';
import { AdminAssistanceActions } from '@/account/data/models';
import { transformAdminAssistanceActions } from '@/account/data/transforms';
import { AdminAssistanceActionsResponse } from '@/account/types';
import { GET_ADMIN_ASSISTANCE_ACTIONS } from './graphql/getAdminAssistanceActions.graphql';

export const getAdminAssistanceActions = async (
  pageSize: number,
  currentPage: number
): Promise<AdminAssistanceActions | null> => {
  return await fetchGraphQl(GET_ADMIN_ASSISTANCE_ACTIONS, {
    method: 'GET',
    cache: 'no-cache',
    variables: {
      pageSize,
      currentPage,
    },
  })
    .then((response: AdminAssistanceActionsResponse) => {
      if (response.errors?.length) return handleFetchError(response.errors);

      return transformAdminAssistanceActions(response);
    })
    .catch(handleNetworkError);
};
