import { handleNetworkError } from '@/account/lib/network-error';
import { fetchGraphQl } from '@/account/api/fetch-graphql';
import { handleFetchError } from '@/account/lib/fetch-error';
import { GET_CUSTOMER_PAYMENT_TOKENS } from './graphql/getCustomerPaymentTokens.graphql';
import { GetCustomerPaymentTokensResponse } from '@/account/types';
import { transformStoredPaymentTokens } from '@/account/data/transforms';
import { StoredPaymentMethodDisplay } from '@/account/data/models/stored-payment-method';

export const getCustomerPaymentTokens = async (
  filterPaymentMethodCodes?: string[]
): Promise<StoredPaymentMethodDisplay[]> => {
  return await fetchGraphQl(GET_CUSTOMER_PAYMENT_TOKENS, {
    method: 'GET',
    cache: 'no-cache',
  })
    .then((response: GetCustomerPaymentTokensResponse) => {
      if (response.errors?.length) return handleFetchError(response.errors);

      const items = response.data?.customerPaymentTokens?.items ?? [];

      return transformStoredPaymentTokens(items, filterPaymentMethodCodes);
    })
    .catch(handleNetworkError);
};
