import { CustomerPaymentTokenItem } from '@/account/types';
import { StoredPaymentMethodDisplay } from '@/account/data/models/stored-payment-method';

/**
 * Maps vault `brand` / legacy `type` codes (Payment Services, Braintree, etc.) to display labels.
 * Keys are uppercase with spaces normalized to underscores.
 */
const CARD_BRAND_LABELS: Record<string, string> = {
  // Legacy short `type` codes
  VI: 'Visa',
  MC: 'Mastercard',
  MD: 'Maestro',
  AE: 'American Express',
  DI: 'Discover',
  DN: 'Diners',
  JCB: 'JCB',
  UN: 'UnionPay',
  // Full `brand` strings (e.g. Adobe Payment Services vault JSON)
  VISA: 'Visa',
  MASTERCARD: 'Mastercard',
  MAESTRO: 'Maestro',
  AMEX: 'American Express',
  AMERICAN_EXPRESS: 'American Express',
  DISCOVER: 'Discover',
  DINERS: 'Diners',
  DINERS_CLUB: 'Diners',
  UNIONPAY: 'UnionPay',
};

type VaultDetails = {
  brand?: string;
  type?: string;
  maskedCC?: string;
  expirationDate?: string;
  lastFour?: string;
  last_four?: string;
  ccLast4?: string;
  cc_last4?: string;
};

function parseVaultDetails(details: string): VaultDetails | null {
  try {
    return JSON.parse(details) as VaultDetails;
  } catch {
    return null;
  }
}

function normalizeBrandKey(value: string): string {
  return value.trim().toUpperCase().replaceAll(/\s+/g, '_');
}

function isUnknownPlaceholder(value: string | undefined): boolean {
  return !value?.trim() || normalizeBrandKey(value) === 'UNKNOWN';
}

function labelForBrandOrTypeCode(code: string | undefined): string | undefined {
  if (!code?.trim()) return undefined;

  return CARD_BRAND_LABELS[normalizeBrandKey(code)];
}

/** Human-readable fallback when the API sends an unmapped brand string. */
function titleCaseBrandFallback(raw: string): string {
  return raw
    .replaceAll('_', ' ')
    .toLowerCase()
    .split(/\s+/)
    .filter(Boolean)
    .map((w) => w.charAt(0).toUpperCase() + w.slice(1))
    .join(' ');
}

function resolveCardBrandLabel(
  parsed: VaultDetails | null,
  item: CustomerPaymentTokenItem
): string {
  const brandRaw = parsed?.brand?.trim();
  const typeRaw = parsed?.type?.trim();

  if (!isUnknownPlaceholder(brandRaw)) {
    const mapped = labelForBrandOrTypeCode(brandRaw);
    if (mapped) return mapped;

    return titleCaseBrandFallback(brandRaw!);
  }

  if (!isUnknownPlaceholder(typeRaw)) {
    const mapped = labelForBrandOrTypeCode(typeRaw);
    if (mapped) return mapped;

    return typeRaw!;
  }

  return item.payment_method_code;
}

/** End of calendar month for MM/YYYY (e.g. 09/2022). */
export function isExpirationDatePast(expirationDate: string | undefined): boolean {
  if (!expirationDate) return false;

  const match = /^(\d{1,2})\/(\d{4})$/.exec(expirationDate.trim());
  if (!match) return false;

  const month = Number.parseInt(match[1], 10);
  const year = Number.parseInt(match[2], 10);
  if (month < 1 || month > 12) return false;

  const endOfExpiryMonth = new Date(year, month, 0, 23, 59, 59, 999);

  return Date.now() > endOfExpiryMonth.getTime();
}

function tokenMatchesFilter(
  item: CustomerPaymentTokenItem,
  filterPaymentMethodCodes: string[]
): boolean {
  return filterPaymentMethodCodes.some(
    (code) =>
      item.payment_method_code === code ||
      item.payment_method_code.startsWith(`${code}_`)
  );
}

/** Prefer {@link PaymentCard} props: last four from common vault `details` shapes. */
function extractLastFourDigits(
  parsed: VaultDetails | null,
  rawDetails: string
): string {
  const fromMasked = (value: string | undefined) => {
    if (!value) return '';
    const digits = value.replaceAll(/\D/g, '');

    return digits.length >= 4 ? digits.slice(-4) : '';
  };

  if (parsed) {
    const direct =
      fromMasked(parsed.maskedCC) ||
      fromMasked(parsed.lastFour) ||
      fromMasked(parsed.last_four) ||
      fromMasked(parsed.ccLast4) ||
      fromMasked(parsed.cc_last4);

    if (direct) return direct;
  }

  return rawDetails.match(/\d{4}/g)?.at(-1) ?? '';
}

/** When details omit card last-four, still drive {@link PaymentCard} with a short stable suffix. */
function fallbackLastFourFromHash(publicHash: string): string {
  const alnum = publicHash.replaceAll(/[^a-zA-Z0-9]/g, '');

  if (alnum.length >= 4) return alnum.slice(-4).toUpperCase();

  return alnum.padEnd(4, '0').slice(0, 4).toUpperCase();
}

function mapTokenToDisplay(
  item: CustomerPaymentTokenItem
): StoredPaymentMethodDisplay | null {
  if (!item.public_hash) return null;

  const parsed = parseVaultDetails(item.details);
  const cardBrand = resolveCardBrandLabel(parsed, item);
  const lastFour =
    extractLastFourDigits(parsed, item.details) ||
    fallbackLastFourFromHash(item.public_hash);

  return {
    publicHash: item.public_hash,
    cardBrand,
    lastFourDigits: lastFour,
    expired: isExpirationDatePast(parsed?.expirationDate),
  };
}

export function transformStoredPaymentTokens(
  items: CustomerPaymentTokenItem[],
  filterPaymentMethodCodes?: string[]
): StoredPaymentMethodDisplay[] {
  const filtered =
    filterPaymentMethodCodes?.length ?
      items.filter((item) => tokenMatchesFilter(item, filterPaymentMethodCodes))
    : items;

  return filtered
    .map((item) => mapTokenToDisplay(item))
    .filter((row): row is StoredPaymentMethodDisplay => row !== null);
}
