import { getCustomerShortResponse } from '@/account/types';
import { CustomerDataModelShort } from '../models/customer';
import { convertToCamelCase } from '@/account/lib/convertCase';
import { config } from '@/account/api';
import { merge } from '@adobe-commerce/elsie/lib';

export const transformCustomer = (
  response: getCustomerShortResponse
): CustomerDataModelShort => {
  const attributeList = response?.data?.customer?.custom_attributes
    ?.filter((el) => el)
    .reduce(
      (
        accumulator: Record<string, string | number | boolean>,
        currentValue
      ) => {
        const key = convertToCamelCase(currentValue.code as string);

        if (currentValue.selected_options?.length) {
          // Select/dropdown attribute — grab the first selected option's value
          accumulator[key] = currentValue.selected_options[0].value ?? '';
        } else {
          // Regular attribute
          accumulator[key] = currentValue.value ?? '';
        }

        return accumulator;
      },
      {} as Record<string, string | number | boolean>
    );

  const model = {
    email: response?.data?.customer?.email || '',
    firstName: response?.data?.customer?.firstname || '',
    lastName: response?.data?.customer?.lastname || '',
    middleName: response?.data?.customer?.middlename || '',
    gender: response?.data?.customer?.gender || '1',
    dateOfBirth: response?.data?.customer?.date_of_birth || '',
    prefix: response?.data?.customer?.prefix || '',
    suffix: response?.data?.customer?.suffix || '',
    createdAt: response?.data?.customer?.created_at || '',
    allowRemoteShoppingAssistance:
      response?.data?.customer?.allow_remote_shopping_assistance,
    ...attributeList,
  };

  return merge(
    model, // default transformer
    config
      ?.getConfig()
      ?.models?.CustomerDataModelShort?.transformer?.(response.data) // custom transformer
  );
};
